import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

function MySortableComponent({ id }) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
  } = useSortable({ id });

  // attributes: Đây là một object chứa các thuộc tính ARIA accessibility (như role, aria-roledescription) và các thuộc tính khác (như tabIndex) để làm cho phần tử có thể focus và tương tác được bằng bàn phím, tuân thủ các tiêu chuẩn về trợ năng.

  // listeners: Đây là một object chứa các event listeners (như onMouseDown, onKeyDown, onTouchStart). Chúng cần được spread (...) vào phần tử DOM để `dnd-kit` có thể lắng nghe các hành động của người dùng (click, nhấn phím, chạm) để bắt đầu quá trình kéo.

  // transform: Một object chứa các giá trị x, y, scaleX, scaleY. Nó đại diện cho sự thay đổi vị trí của phần tử khi nó được kéo hoặc khi các phần tử khác sắp xếp lại. Nó được dùng để tính toán giá trị cho thuộc tính CSS `transform`, tạo hiệu ứng di chuyển mượt mà thay vì thay đổi vị trí đột ngột.

  // transition: Một chuỗi CSS (ví dụ: 'transform 250ms ease'). Nó được dùng cho thuộc tính CSS `transition` để định nghĩa hiệu ứng chuyển động khi phần tử thay đổi vị trí (do `transform` thay đổi), giúp animation trở nên mượt mà hơn.

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  return (
    <div ref={setNodeRef} style={style} {...attributes} {...listeners}>
      {id}
    </div>
  );
}
